import{_ as a,o as r,c as t,a6 as s,eo as p,i8 as l,i9 as e,ep as o,ia as n,ib as g,ic as _,id as m,ie as c,ig as d,fx as h,ih as x,ii as b,ij as f,ik as k,il as P,im as u,io as S,ip as T,iq as $}from"./chunks/framework.UYVGz2W_.js";const D=JSON.parse('{"title":"クライアントとしてのスタート","description":"","frontmatter":{},"headers":[],"relativePath":"ja/getting-started-client/index.md","filePath":"ja/getting-started-client/index.md"}'),j={name:"ja/getting-started-client/index.md"};function A(E,i,N,V,v,B){return r(),t("div",null,[...i[0]||(i[0]=[s('<h1 id="クライアントとしてのスタート" tabindex="-1">クライアントとしてのスタート <a class="header-anchor" href="#クライアントとしてのスタート" aria-label="Permalink to “クライアントとしてのスタート”">​</a></h1><h2 id="最初の接続" tabindex="-1">最初の接続 <a class="header-anchor" href="#最初の接続" aria-label="Permalink to “最初の接続”">​</a></h2><p>最初の接続の際には、お客様の連絡先情報をプロフィールにご記入いただくことをお勧めいたします。 画面右上の名前をクリックし（1）、次に<strong>プロフィール</strong>をクリックします（2）。</p><p>注：この<strong>ドキュメント</strong>へのリンクが利用可能です（4）。 また、このメニューで<strong>ダークテーマ</strong>に切り替えることもできます（3）。また、Slack（5）にアクセスしたり、ロードマップ（6）を確認することもできます。</p><p><img src="'+p+'" alt="ユーザープロファイル"></p><p>この新しいページでは、名前 (1) (2)、メールアドレス (3)、電話番号 (4)、 タイムゾーン (5)、ウェブサイトの言語 (6) を変更したり、 アバターとして自分の写真を投稿 (7) することができます。 誰が何をしているのかがわかりやすくなります。</p><p><img src="'+l+'" alt="ユーザー詳細"></p><p>また、通知を希望する場合は、メールまたはSlackのどちらかを選択できます。</p><p><img src="'+e+'" alt="ユーザー詳細"></p><p>さらに下にスクロールすると、必要に応じてパスワードを変更することもできます。 デフォルトのパスワードは、ご自身で設定したパスワードに変更することをお勧めします。</p><p><img src="'+o+'" alt="ユーザーパスワード"></p><h2 id="プレイリストの確認" tabindex="-1">プレイリストの確認 <a class="header-anchor" href="#プレイリストの確認" aria-label="Permalink to “プレイリストの確認”">​</a></h2><p><strong>Kitsu</strong> における中心となるページは <strong>プレイリスト</strong> ページです。 プロダクション アバターをクリックすると、このページにアクセスできます。</p><p><img src="'+n+'" alt="クライアント ランディングページ"></p><p>プロダクション アバターをクリックすると、<strong>プレイリスト</strong> ページに移動します。</p><p>プレイリストには、あなたがコメントするアセットやショットがすべて集められます。</p><p><img src="'+g+'" alt="クライアントプレイリストのグローバルページ"></p><p>左側では、<strong>タスクタイプ</strong>、<strong>日付</strong>、または<strong>名前</strong>（1）ごとにプレイリストをソートし、次に作成されたプレイリストのリスト（2）を表示することができます。中央部分では、最新のプレイリストに素早くアクセスできます（3）。</p><h3 id="プレイリストの詳細" tabindex="-1">プレイリストの詳細 <a class="header-anchor" href="#プレイリストの詳細" aria-label="Permalink to “プレイリストの詳細”">​</a></h3><p>左側では、さまざまなプレイリストにアクセスできます。中央では、選択したプレイリストのさまざまな要素が表示されます。アセットまたはショットです。右側では、コメントセクションにアクセスできます。</p><p><img src="'+_+'" alt="クライアントプレイリストのグローバルページ"></p><p>コメントパネルでは、プレビューを承認するコメントを入力できます。</p><p><img src="'+m+'" alt="クライアントプレイリストのグローバルページ"></p><p>要素（アセットまたはショット）の上部には、さまざまなオプションへのアクセスがあります。</p><p><img src="'+c+'" alt="クライアントプレイリストのオプション"></p><ul><li>(1) 前ショット/アセット *(2) 次ショット/アセット</li><li>(3) 要素の位置</li><li>(4) 再生/一時停止ボタン</li><li>(5) 速度を変更できます：x1..0、x0.50、x0.25</li><li>(6) 選択したショットをループ再生</li><li>(7) ショットの実際のタイムコード/グローバルタイムコード</li><li>(8) 実際のフレーム</li><li>(9) 前フレーム</li><li>(10) 次フレーム</li><li>(11) スプリットスクリーン：2つのタスクタイプを並べて比較できます</li><li>(12) アノテーションの取り消し</li><li>(13) アノテーションのやり直し</li><li>(14) 画像上にコメントを書き込み、テキストの色を変更</li><li>(15) 画像上にコメントを書き込み、線の色とサイズを変更</li><li>(16) 描画を選択し、×をクリックして削除する</li><li>(17) プレイリスト内のすべての要素のタスクタイプを変更する</li><li>(18) コメントを投稿し、ステータスを変更するためのパネルセクションを開く</li><li>(19) 要素のリストを隠す</li><li>(20) プレイリストをダウンロードする</li><li>(21) フルスクリーン</li></ul><h2 id="コメントを共有" tabindex="-1">コメントを共有 <a class="header-anchor" href="#コメントを共有" aria-label="Permalink to “コメントを共有”">​</a></h2><p>まず、コメントセクションを開きます。 <img src="'+d+'" alt="コメントボタン"></p><p>そこから、アーティストに変更を依頼したい場合は、ステータスを <img src="'+h+'" alt="再撮影"> に変更できます。</p><p>コメントに<strong>チェックリスト</strong>を追加できます。</p><p>「チェックリストを追加」ボタンをクリックすると、チェックリストの最初の項目が表示されます。</p><p><img src="'+x+'" alt="クライアントがチェックリストを追加"></p><p>コメントを入力し、<strong>Enter</strong>キーを押してチェックリストに別の行を追加するか、または「チェックリストを追加」ボタンを再度クリックします。</p><p><img src="'+b+'" alt="チェックリスト"></p><h2 id="アセットのグローバルビュー" tabindex="-1">アセットのグローバルビュー <a class="header-anchor" href="#アセットのグローバルビュー" aria-label="Permalink to “アセットのグローバルビュー”">​</a></h2><p>クライアントとして、画面上部のドロップダウンメニューからアセットのグローバルページに移動できます。</p><p><img src="'+f+'" alt="クライアントのドロップダウンメニュー アセット"></p><p>グローバルページでは、アセットの各ステップのステータスをすべて確認できます。</p><p><img src="'+k+'" alt="クライアントのグローバルページ アセット"></p><h2 id="ショットのグローバルビュー" tabindex="-1">ショットのグローバルビュー <a class="header-anchor" href="#ショットのグローバルビュー" aria-label="Permalink to “ショットのグローバルビュー”">​</a></h2><p>クライアントとして、画面上部のドロップダウンメニューからショットのグローバルページに移動できます。</p><p><img src="'+P+'" alt="クライアントのドロップダウンメニュー ショット"></p><p>グローバルページでは、ショットの各ステップのステータスをすべて確認できます。</p><p><img src="'+u+'" alt="クライアントのグローバルページショット"></p><h2 id="制作レポート" tabindex="-1">制作レポート <a class="header-anchor" href="#制作レポート" aria-label="Permalink to “制作レポート”">​</a></h2><p>スタジオとのコミュニケーションを円滑にするため、制作レポートに直接アクセスできます。レポートは、<strong>シーケンス統計</strong>と<strong>アセットタイプ統計</strong>の2つの部分に分かれています</p><p><img src="'+S+'" alt="クライアントのドロップダウンメニューのシーケンス統計"></p><p><strong>シーケンス統計</strong>ページはリアルタイムで更新されます。このページを見るたびに、最新の情報が確認できます。</p><p><img src="'+T+'" alt="クライアントのシーケンス統計"></p><p>ショット数またはフレーム数ごとの統計を表示するように選択できます。</p><p>また、<strong>表示モード</strong>を変更することもできます。<strong>円グラフ</strong>表示から <strong>カウント</strong>表示に切り替えることができます。</p><p><img src="'+$+'" alt="クライアントシーケンス統計カウント"></p><p>この表示をダウンロードして、制作の進捗状況を追跡することができます。</p>',53)])])}const I=a(j,[["render",A]]);export{D as __pageData,I as default};
